interface PreloaderProps {
  onComplete: () => void;
}

const DRAW_DURATION = 0.88;
const STAGGER = 0.22;

export default function Preloader({ onComplete }: PreloaderProps) {
  const [phase, setPhase] = useState<"loading" | "complete" | "exit">(
    "loading",
  );
  const [svgX, setSvgX] = useState(-24);
  const [svgY, setSvgY] = useState(55);
  const [svgScale, setSvgScale] = useState(1.0);
  const pathRefs = useRef<(SVGPathElement | null)[]>([]);
  const rafRef = useRef<number>(0);
  const [isExiting, setIsExiting] = useState(false);
  const [ready, setReady] = useState(false);

  useLayoutEffect(() => {
    pathRefs.current.forEach((el) => {
      if (!el) return;
      const len = el.getTotalLength();
      el.style.setProperty("--len", `${len}px`);
    });
    setReady(true);
  }, []);

  useEffect(() => {
    // document.body.style.overflow = "hidden";

    // Total duration matching your visual sequence
    const timer = setTimeout(() => {
      setIsExiting(true);
      setTimeout(() => {
        document.body.style.overflow = "";
        onComplete();
      }, 1400); // Matches CSS transition duration
    }, 4500);

    return () => clearTimeout(timer);
  }, [onComplete]);

  if (phase === "exit") return null;

  const pngDelay = (0.3 + PATHS.length * STAGGER + DRAW_DURATION + 0.2).toFixed(
    2,
  );
  const svgFadeDelay = pngDelay;

  return (
    <div
      aria-hidden="true"
      className={isExiting ? "pl-container exiting" : "pl-container"}
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 9999,
        background: "#FDFAF4",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        overflow: "hidden",
        animation:
          phase === "complete"
            ? "pl-exit 1.4s cubic-bezier(0.87,0,0.13,1) 0.9s forwards"
            : undefined,
        transition: "opacity 1.4s ease-in-out",
        opacity: isExiting ? 0 : 1, // Smooth fade out
      }}
    >
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=STIX+Two+Text:ital,wght@0,400;0,700;1,400&family=Cormorant+Garamond:ital,wght@0,300;1,300&family=Jost:wght@400;700&display=swap');
  .path-el {
  opacity: 0;
  stroke-dasharray: var(--len);
  stroke-dashoffset: var(--len);
}
.path-el.is-drawing {
  animation: draw ${DRAW_DURATION}s cubic-bezier(0.45,0,0.15,1) both;
}
@keyframes draw {
  0%   { stroke-dashoffset: var(--len); opacity: 1; }
  100% { stroke-dashoffset: 0;          opacity: 1; }
}
        @keyframes pl-up {
          from { opacity: 0; transform: translateY(14px); }
          to   { opacity: 1; transform: translateY(0); }
        }
        @keyframes pl-lh {
          from { transform: scaleX(0); opacity: 0; }
          to   { transform: scaleX(1); opacity: 1; }
        }
        @keyframes pl-lv {
          from { transform: scaleY(0); opacity: 0; }
          to   { transform: scaleY(1); opacity: 1; }
        }
        @keyframes pl-corner { from { opacity:0; } to { opacity:1; } }
        @keyframes draw {
          0%   { stroke-dashoffset: var(--len); opacity: 1; }
          100% { stroke-dashoffset: 0; opacity: 1; }
        }
        @keyframes logo-png-in {
          from { opacity: 0; }
          to   { opacity: 1; }
        }
        @keyframes svg-fade-out {
          from { opacity: 1; }
          to   { opacity: 0; }
        }
        @keyframes pl-bob {
          0%,100% { transform: translateY(0); }
          50%     { transform: translateY(-9px); }
        }
        .pl-lh     { animation: pl-lh 1.4s cubic-bezier(0.76,0,0.24,1) 0.05s both; transform: scaleX(0); }
        .pl-lv     { animation: pl-lv 1.4s cubic-bezier(0.76,0,0.24,1) 0.18s both; transform: scaleY(0); }
        .pl-cr     { animation: pl-corner 0.9s ease 0.08s both; opacity: 0; }
        .pl-bob    { animation: pl-bob 3.8s ease-in-out 4.2s infinite; }
        .pl-name   { animation: pl-up 1s cubic-bezier(0.22,1,0.36,1) 3.9s both; opacity: 0; }
      `}</style>

      {/* ── Ivory wash ── */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          pointerEvents: "none",
          background:
            "radial-gradient(ellipse 65% 55% at 50% 50%, #F0E5CE 0%, #FDFAF4 58%, #F5EDD8 100%)",
        }}
      />

      {/* ── Frame edges ── */}
      <div
        className="pl-lh"
        style={{
          position: "absolute",
          top: 26,
          left: "8%",
          right: "8%",
          height: 1,
          background:
            "linear-gradient(90deg,transparent,rgba(202,140,25,0.45) 15%,rgba(202,140,25,0.45) 85%,transparent)",
          transformOrigin: "left",
        }}
      />
      <div
        className="pl-lh"
        style={{
          position: "absolute",
          bottom: 26,
          left: "8%",
          right: "8%",
          height: 1,
          background:
            "linear-gradient(90deg,transparent,rgba(202,140,25,0.45) 15%,rgba(202,140,25,0.45) 85%,transparent)",
          transformOrigin: "right",
          animationDelay: "0.08s",
        }}
      />
      <div
        className="pl-lv"
        style={{
          position: "absolute",
          left: 26,
          top: "10%",
          bottom: "10%",
          width: 1,
          background:
            "linear-gradient(180deg,transparent,rgba(202,140,25,0.28) 20%,rgba(202,140,25,0.28) 80%,transparent)",
          transformOrigin: "top",
        }}
      />
      <div
        className="pl-lv"
        style={{
          position: "absolute",
          right: 26,
          top: "10%",
          bottom: "10%",
          width: 1,
          background:
            "linear-gradient(180deg,transparent,rgba(202,140,25,0.28) 20%,rgba(202,140,25,0.28) 80%,transparent)",
          transformOrigin: "bottom",
          animationDelay: "0.08s",
        }}
      />

      {/* ── Corners ── */}
      {(
        [
          { s: { top: 18, left: 18 }, f: "none" },
          { s: { top: 18, right: 18 }, f: "scaleX(-1)" },
          { s: { bottom: 18, left: 18 }, f: "scaleY(-1)" },
          { s: { bottom: 18, right: 18 }, f: "scale(-1,-1)" },
        ] as const
      ).map((c, i) => (
        <div
          key={i}
          className="pl-cr"
          style={{
            position: "absolute",
            width: 64,
            height: 64,
            zIndex: 4,
            transform: c.f,
            ...c.s,
          }}
        >
          <svg
            viewBox="0 0 64 64"
            fill="none"
            style={{ width: "100%", height: "100%" }}
          >
            <line
              x1="1"
              y1="1"
              x2="50"
              y2="1"
              stroke="rgba(202,140,25,0.6)"
              strokeWidth="1"
            />
            <line
              x1="1"
              y1="1"
              x2="1"
              y2="50"
              stroke="rgba(202,140,25,0.6)"
              strokeWidth="1"
            />
            <line
              x1="14"
              y1="1"
              x2="14"
              y2="14"
              stroke="rgba(202,140,25,0.22)"
              strokeWidth="0.5"
            />
            <line
              x1="1"
              y1="14"
              x2="14"
              y2="14"
              stroke="rgba(202,140,25,0.22)"
              strokeWidth="0.5"
            />
            <rect
              x="-1.5"
              y="-1.5"
              width="5"
              height="5"
              fill="#CA8C19"
              opacity="0.85"
              transform="rotate(45 1 1)"
            />
            <circle cx="50" cy="1" r="1.5" fill="rgba(202,140,25,0.35)" />
            <circle cx="1" cy="50" r="1.5" fill="rgba(202,140,25,0.35)" />
          </svg>
        </div>
      ))}

      {/* ══ CENTER ══ */}
      <div
        style={{
          position: "relative",
          zIndex: 3,
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
        }}
      >
        {/* Logo container */}
        <div
          className="pl-bob"
          style={{
            position: "relative",
            width: "clamp(180px, 28vw, 300px)",
            height: "clamp(180px, 28vw, 300px)",
            marginBottom: "clamp(16px, 2vw, 32px)",
          }}
        >
          {/* SVG stroke draw-in */}
          <svg
            viewBox="0 0 1972.16 2552"
            style={{
              position: "absolute",
              inset: 0,
              width: "100%",
              height: "100%",
              overflow: "visible",
            }}
          >
            <defs>
              <linearGradient id="navyGrad" x1="15%" y1="0%" x2="85%" y2="100%">
                <stop offset="0%" stopColor="#1A5276" />
                <stop offset="50%" stopColor="#0F395C" />
                <stop offset="100%" stopColor="#061629" />
              </linearGradient>
            </defs>
            <g
              transform={`translate(${svgX}, ${svgY}) scale(${svgScale})`}
              style={{
                transformOrigin: "986px 1276px",
                animation: `svg-fade-out 0.8s ease ${svgFadeDelay}s forwards`,
              }}
            >
              {PATHS.map((p, i) => {
                const delay = 0.3 + i * STAGGER;
                return (
                  <path
                    key={i}
                    ref={(el) => {
                      pathRefs.current[i] = el;
                    }}
                    className={ready ? "path-el is-drawing" : "path-el"}
                    d={p.d}
                    fill="none"
                    stroke="url(#navyGrad)"
                    strokeWidth={18}
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    style={{ animationDelay: `${delay}s` }}
                  />
                );
              })}
            </g>
          </svg>

          {/* PNG fades in once strokes complete */}
          <img
            src="/assets/images/continental-logo-03.png"
            alt="Continental Group"
            style={{
              position: "absolute",
              inset: 0,
              width: "100%",
              height: "100%",
              objectFit: "contain",
              opacity: 0,
              animation: `logo-png-in 0.8s ease ${pngDelay}s both`,
            }}
          />
        </div>

        {/* Name */}
        <div
          className="pl-name"
          style={{
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            gap: "clamp(2px, 0.4vw, 5px)",
          }}
        >
          <div
            style={{
              fontFamily:
                "'STIX Two Text', 'Cormorant Garamond', Georgia, serif",
              fontSize: "clamp(26px, 5vw, 68px)",
              fontWeight: 400,
              letterSpacing: "clamp(0.16em, 1.2vw, 0.28em)",
              textTransform: "uppercase",
              color: "#0F395C",
              lineHeight: 1,
              whiteSpace: "nowrap",
            }}
          >
            Continental Group
          </div>
          {/* <div style={{
                        fontFamily: "'STIX Two Text', 'Cormorant Garamond', Georgia, serif",
                        fontSize: "clamp(10px, 1.8vw, 24px)",
                        fontWeight: 400,
                        letterSpacing: "clamp(0.3em, 1.8vw, 0.5em)",
                        textTransform: "uppercase",
                        color: "#0F395C",
                        lineHeight: 1,
                        whiteSpace: "nowrap",
                    }}>
                        Group
                    </div> */}
        </div>
      </div>

      {/* ── DEV MODE: Alignment Editor ── */}
      {DEV_MODE && (
        <div
          style={{
            position: "fixed",
            bottom: 16,
            left: "50%",
            transform: "translateX(-50%)",
            zIndex: 99999,
            background: "rgba(15,57,92,0.95)",
            backdropFilter: "blur(12px)",
            border: "1px solid rgba(202,140,25,0.4)",
            borderRadius: 8,
            padding: "12px 20px",
            display: "flex",
            flexDirection: "column",
            gap: 10,
            minWidth: 320,
            fontFamily: "'Jost', sans-serif",
            fontSize: 11,
            color: "#F5EDD8",
          }}
        >
          <div
            style={{
              fontSize: 9,
              fontWeight: 700,
              letterSpacing: "0.3em",
              textTransform: "uppercase",
              color: "rgba(202,140,25,0.8)",
              marginBottom: 2,
            }}
          >
            SVG Alignment Editor
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <label
              style={{
                width: 60,
                fontSize: 10,
                color: "rgba(245,237,216,0.6)",
              }}
            >
              X offset
            </label>
            <input
              type="range"
              min={-200}
              max={200}
              step={1}
              value={svgX}
              onChange={(e) => setSvgX(Number(e.target.value))}
              style={{ flex: 1 }}
            />
            <span
              style={{
                width: 36,
                textAlign: "right",
                color: "#EEC06B",
                fontWeight: 700,
              }}
            >
              {svgX}
            </span>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <label
              style={{
                width: 60,
                fontSize: 10,
                color: "rgba(245,237,216,0.6)",
              }}
            >
              Y offset
            </label>
            <input
              type="range"
              min={-200}
              max={200}
              step={1}
              value={svgY}
              onChange={(e) => setSvgY(Number(e.target.value))}
              style={{ flex: 1 }}
            />
            <span
              style={{
                width: 36,
                textAlign: "right",
                color: "#EEC06B",
                fontWeight: 700,
              }}
            >
              {svgY}
            </span>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <label
              style={{
                width: 60,
                fontSize: 10,
                color: "rgba(245,237,216,0.6)",
              }}
            >
              Scale
            </label>
            <input
              type="range"
              min={0.5}
              max={2}
              step={0.01}
              value={svgScale}
              onChange={(e) => setSvgScale(Number(e.target.value))}
              style={{ flex: 1 }}
            />
            <span
              style={{
                width: 36,
                textAlign: "right",
                color: "#EEC06B",
                fontWeight: 700,
              }}
            >
              {svgScale.toFixed(2)}
            </span>
          </div>
          <div
            style={{
              marginTop: 4,
              paddingTop: 8,
              borderTop: "1px solid rgba(202,140,25,0.2)",
              fontSize: 10,
              color: "rgba(245,237,216,0.5)",
            }}
          >
            Copy:{" "}
            <span style={{ color: "#EEC06B" }}>
              translate({svgX}, {svgY}) scale({svgScale.toFixed(2)})
            </span>
          </div>
        </div>
      )}
    </div>
  );
}
